   652→    const { responses } = req.body;
   653→    const assessmentId = req.params.id;
   654→
   655→    // Get the assessment
   656→    const assessment = await pool.query(
   657→      'SELECT * FROM skill_assessments WHERE id = $1 AND user_id = $2',
   658→      [assessmentId, req.user.id]
   659→    );
   660→
   661→    if (assessment.rows.length === 0) {
   662→      return res.status(404).json({ error: 'Assessment not found' });
   663→    }
   664→
   665→    const questions = assessment.rows[0].questions;
   666→
   667→    // Get skill name for evaluation
   668→    let skillName = assessment.rows[0].title.replace(' Assessment', '');
   669→    if (assessment.rows[0].skill_id) {
   670→      const skill = await pool.query('SELECT skill_name FROM candidate_skills WHERE id = $1', [assessment.rows[0].skill_id]);
   671→      if (skill.rows.length > 0) skillName = skill.rows[0].skill_name;
