        correctAnswer: q ? q.correct_answer : null,
        explanation: q ? q.explanation : null,
        difficulty: q ? q.difficulty_level : null,
      };
    });

    res.json({
      assessment: {
        ...assessment,
        detailedAnswers,
      },
    });
