import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Select } from '@/components/ui/select'
import {
  Briefcase, MapPin, DollarSign, Clock, Search, Building2, ArrowRight,
} from 'lucide-react'

interface Job {
  id: number
  title: string
  company: string
  poster_company?: string
  description: string
  requirements: string
  location: string
  salary_range: string
  job_type: string
  status: string
  created_at: string
  screening_questions?: string
}

export function CandidateJobsPage() {
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [typeFilter, setTypeFilter] = useState('')
  const [locationFilter, setLocationFilter] = useState('')

  useEffect(() => {
    loadJobs()
  }, [])

  async function loadJobs() {
    try {
      const data = await apiCall<{ jobs: Job[] }>('/jobs?status=active&limit=100')
      setJobs(data.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  const filtered = jobs.filter(j => {
    const matchSearch = !search ||
      j.title?.toLowerCase().includes(search.toLowerCase()) ||
      j.company?.toLowerCase().includes(search.toLowerCase()) ||
      j.description?.toLowerCase().includes(search.toLowerCase())
    const matchType = !typeFilter || j.job_type === typeFilter
    const matchLocation = !locationFilter || j.location?.toLowerCase().includes(locationFilter.toLowerCase())
    return matchSearch && matchType && matchLocation
  })

  const jobTypes = [...new Set(jobs.map(j => j.job_type).filter(Boolean))]

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)} months ago`
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">Job Board</h1>
        <p className="text-muted-foreground">Find your next opportunity</p>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="p-4">
          <div className="flex flex-col gap-3 sm:flex-row">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                placeholder="Search jobs by title, company, or keywords..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                className="pl-9"
              />
            </div>
            <Select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} className="sm:w-40">
              <option value="">All Types</option>
              {jobTypes.map(t => <option key={t} value={t}>{t}</option>)}
            </Select>
            <Input
              placeholder="Location..."
              value={locationFilter}
              onChange={e => setLocationFilter(e.target.value)}
              className="sm:w-40"
            />
          </div>
        </CardContent>
      </Card>

      {/* Results count */}
      <p className="text-sm text-muted-foreground">{filtered.length} jobs found</p>

      {/* Job list */}
      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No jobs found matching your criteria</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtered.map(job => (
            <Link key={job.id} to={`/candidate/jobs/${job.id}`}>
              <Card className="transition-shadow hover:shadow-md cursor-pointer">
                <CardContent className="p-5">
                  <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-semibold text-base truncate">{job.title}</h3>
                        {(() => {
                          try {
                            return job.screening_questions && JSON.parse(job.screening_questions).length > 0
                          } catch { return false }
                        })() && (
                          <Badge variant="outline" className="text-[10px] shrink-0">Screening</Badge>
                        )}
                      </div>
                      <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground mb-2">
                        <span className="flex items-center gap-1">
                          <Building2 className="h-3.5 w-3.5" />
                          {job.company || job.poster_company || 'Company'}
                        </span>
                        {job.location && (
                          <span className="flex items-center gap-1">
                            <MapPin className="h-3.5 w-3.5" />
                            {job.location}
                          </span>
                        )}
                        {job.salary_range && (
                          <span className="flex items-center gap-1">
                            <DollarSign className="h-3.5 w-3.5" />
                            {job.salary_range}
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-muted-foreground line-clamp-2">
                        {job.description?.substring(0, 200)}
                      </p>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <div className="flex flex-col items-end gap-1">
                        {job.job_type && <Badge variant="secondary">{job.job_type}</Badge>}
                        <span className="flex items-center gap-1 text-xs text-muted-foreground">
                          <Clock className="h-3 w-3" />
                          {timeAgo(job.created_at)}
                        </span>
                      </div>
                      <ArrowRight className="h-4 w-4 text-muted-foreground" />
                    </div>
                  </div>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Dialog, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog'
import {
  FileText, Building2, MapPin, Calendar, ExternalLink, XCircle, AlertTriangle,
  Clock, CheckCircle, Briefcase, DollarSign, Filter, ClipboardList,
  ArrowRight, Eye,
} from 'lucide-react'

interface ScreeningQuestion {
  question: string
  type: 'text' | 'yes_no' | 'select'
  required?: boolean
  options?: string[]
  category?: string
}

interface Application {
  id: number
  job_id: number
  status: string
  title: string
  company: string
  location: string
  salary_range: string
  job_type: string
  posted_by_company?: string
  applied_at: string
  updated_at: string
  match_score?: number
  cover_letter?: string
  screening_answers?: string | Record<string, string>
  screening_questions?: string | ScreeningQuestion[]
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: typeof Clock }> = {
  applied: { label: 'Applied', variant: 'secondary', icon: FileText },
  reviewing: { label: 'Under Review', variant: 'warning', icon: Eye },
  shortlisted: { label: 'Shortlisted', variant: 'default', icon: CheckCircle },
  interviewed: { label: 'Interviewed', variant: 'default', icon: Briefcase },
  offered: { label: 'Offer Received', variant: 'success', icon: DollarSign },
  hired: { label: 'Hired', variant: 'success', icon: CheckCircle },
  rejected: { label: 'Not Selected', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: XCircle },
}

export function CandidateApplicationsPage() {
  const [applications, setApplications] = useState<Application[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [withdrawTarget, setWithdrawTarget] = useState<Application | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [selectedApp, setSelectedApp] = useState<Application | null>(null)

  useEffect(() => {
    loadApplications()
  }, [])

  async function loadApplications() {
    try {
      const data = await apiCall<{ success: boolean; applications: Application[] }>('/candidate/applications')
      setApplications(data.applications || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function withdrawApplication() {
    if (!withdrawTarget) return
    setWithdrawing(true)
    try {
      await apiCall(`/candidate/applications/${withdrawTarget.id}/withdraw`, {
        method: 'PUT',
      })
      setApplications(prev =>
        prev.map(a => a.id === withdrawTarget.id ? { ...a, status: 'withdrawn' } : a)
      )
      setWithdrawTarget(null)
      setSelectedApp(null)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw application')
    } finally {
      setWithdrawing(false)
    }
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return 'Yesterday'
    if (days < 7) return `${days} days ago`
    if (days < 30) return `${Math.floor(days / 7)} weeks ago`
    return `${Math.floor(days / 30)} months ago`
  }

  function parseScreeningData(app: Application) {
    try {
      const answers = typeof app.screening_answers === 'string'
        ? JSON.parse(app.screening_answers)
        : app.screening_answers
      const questions: ScreeningQuestion[] = typeof app.screening_questions === 'string'
        ? JSON.parse(app.screening_questions)
        : (app.screening_questions || [])
      return { answers, questions }
    } catch {
      return { answers: null, questions: [] }
    }
  }

  const statuses = ['applied', 'reviewing', 'shortlisted', 'interviewed', 'offered', 'hired', 'rejected', 'withdrawn']
  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applications.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = applications.filter(a => !statusFilter || a.status === statusFilter)

  const active = filtered.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status))
  const completed = filtered.filter(a => ['rejected', 'withdrawn', 'hired'].includes(a.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Applications</h1>
        <p className="text-muted-foreground">Track your job application status and manage active applications</p>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applications.length}</p>
            <p className="text-xs text-muted-foreground">Total Applied</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {applications.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Active</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {applications.filter(a => ['reviewing', 'interviewed'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">In Progress</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {applications.filter(a => ['offered', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Offers / Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({applications.length})
        </Button>
        {statuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : applications.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <FileText className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">You haven't applied to any jobs yet</p>
            <Link to="/candidate/jobs">
              <Button>Browse Jobs</Button>
            </Link>
          </CardContent>
        </Card>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Filter className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No applications match this filter</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {active.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Active Applications ({active.length})</h2>
              <div className="space-y-3">
                {active.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onWithdraw={() => setWithdrawTarget(app)}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}

          {completed.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Completed ({completed.length})</h2>
              <div className="space-y-3">
                {completed.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Application detail dialog */}
      {selectedApp && (
        <Dialog open={true} onClose={() => setSelectedApp(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedApp.title}</DialogTitle>
            <DialogDescription>
              {selectedApp.company || selectedApp.posted_by_company || 'Company'}
              {selectedApp.location ? ` • ${selectedApp.location}` : ''}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedApp.status] || { label: selectedApp.status, variant: 'secondary' as const, icon: Clock }
              return <Badge variant={config.variant} className="w-fit">{config.label}</Badge>
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Applied
                </p>
                <p className="font-medium">{new Date(selectedApp.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Clock className="h-3 w-3" /> Last Update
                </p>
                <p className="font-medium">{timeAgo(selectedApp.updated_at)}</p>
              </div>
              {selectedApp.salary_range && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <DollarSign className="h-3 w-3" /> Salary
                  </p>
                  <p className="font-medium">{selectedApp.salary_range}</p>
                </div>
              )}
              {selectedApp.match_score && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground">Match Score</p>
                  <p className="font-medium text-primary">{selectedApp.match_score}%</p>
                </div>
              )}
            </div>

            {/* Progress timeline */}
            <ApplicationTimeline status={selectedApp.status} appliedAt={selectedApp.applied_at} updatedAt={selectedApp.updated_at} />

            {/* Cover letter */}
            {selectedApp.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1">Your Cover Letter</h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap max-h-40 overflow-y-auto">
                  {selectedApp.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            <ScreeningAnswersSection app={selectedApp} parseScreeningData={parseScreeningData} />

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              <Link to={`/candidate/jobs/${selectedApp.job_id}`} className="flex-1">
                <Button variant="outline" className="gap-2 w-full">
                  <ExternalLink className="h-4 w-4" /> View Job
                </Button>
              </Link>
              {!['rejected', 'withdrawn', 'hired'].includes(selectedApp.status) && (
                <Button
                  variant="outline"
                  onClick={() => {
                    setSelectedApp(null)
                    setWithdrawTarget(selectedApp)
                  }}
                  className="gap-2 text-destructive hover:text-destructive"
                >
                  <XCircle className="h-4 w-4" /> Withdraw
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Withdraw confirmation dialog */}
      {withdrawTarget && (
        <Dialog open={true} onClose={() => !withdrawing && setWithdrawTarget(null)} className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-amber-500" />
              Withdraw Application?
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Are you sure you want to withdraw your application for{' '}
              <strong>{withdrawTarget.title}</strong> at{' '}
              <strong>{withdrawTarget.company || withdrawTarget.posted_by_company || 'this company'}</strong>?
            </p>
            <div className="rounded-lg bg-amber-50 border border-amber-200 p-3 text-sm text-amber-800">
              This action cannot be undone. You may need to reapply if you change your mind.
            </div>
            <div className="flex gap-2 pt-2">
              <Button
                variant="outline"
                onClick={() => setWithdrawTarget(null)}
                disabled={withdrawing}
                className="flex-1"
              >
                Keep Application
              </Button>
              <Button
                variant="destructive"
                onClick={withdrawApplication}
                disabled={withdrawing}
                className="gap-2 flex-1"
              >
                {withdrawing ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <XCircle className="h-4 w-4" />
                )}
                Withdraw
              </Button>
            </div>
          </div>
        </Dialog>
      )}
    </div>
  )
}

function ScreeningAnswersSection({
  app,
  parseScreeningData,
}: {
  app: Application
  parseScreeningData: (app: Application) => { answers: Record<string, string> | null; questions: ScreeningQuestion[] }
}) {
  const { answers, questions } = parseScreeningData(app)

  if (!answers || Object.keys(answers).length === 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
        <ClipboardList className="h-4 w-4 text-primary" />
        Your Screening Answers
      </h4>
      <div className="space-y-2">
        {Object.entries(answers).map(([key, value], i) => {
          const q = questions[i]
          const questionText = q?.question || q || `Question ${i + 1}`
          return (
            <div key={key} className="rounded-lg bg-muted/50 p-3">
              <p className="text-xs text-muted-foreground mb-1 font-medium">
                {String(questionText)}
              </p>
              <p className="text-sm">{String(value)}</p>
            </div>
          )
        })}
      </div>
    </div>
  )
}

function ApplicationTimeline({ status, appliedAt, updatedAt }: { status: string; appliedAt: string; updatedAt: string }) {
  const steps = [
    { key: 'applied', label: 'Applied', icon: FileText },
    { key: 'reviewing', label: 'Review', icon: Eye },
    { key: 'interviewed', label: 'Interview', icon: Briefcase },
    { key: 'offered', label: 'Offer', icon: CheckCircle },
  ]

  const stepIndex = {
    applied: 0, reviewing: 1, shortlisted: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[status] ?? 0

  // Special terminal states
  if (status === 'rejected' || status === 'withdrawn') {
    const config = statusConfig[status]
    return (
      <div>
        <h4 className="font-medium text-sm mb-3">Status Timeline</h4>
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <div className="flex h-8 w-8 items-center justify-center rounded-full border-2 border-primary bg-primary/10">
              <FileText className="h-4 w-4 text-primary" />
            </div>
            <div>
              <p className="text-sm font-medium">Applied</p>
              <p className="text-xs text-muted-foreground">{new Date(appliedAt).toLocaleDateString()}</p>
            </div>
          </div>
          <div className="ml-4 h-4 w-px bg-muted" />
          <div className="flex items-center gap-3">
            <div className={`flex h-8 w-8 items-center justify-center rounded-full border-2 ${
              status === 'rejected' ? 'border-destructive bg-destructive/10' : 'border-muted bg-muted/50'
            }`}>
              <XCircle className={`h-4 w-4 ${status === 'rejected' ? 'text-destructive' : 'text-muted-foreground'}`} />
            </div>
            <div>
              <p className="text-sm font-medium">{config.label}</p>
              <p className="text-xs text-muted-foreground">{new Date(updatedAt).toLocaleDateString()}</p>
            </div>
          </div>
        </div>
      </div>
    )
  }

  if (stepIndex < 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-3">Progress</h4>
      <div className="flex items-center gap-1">
        {steps.map((step, i) => {
          const isComplete = i <= stepIndex
          const isCurrent = i === stepIndex
          const Icon = step.icon
          return (
            <div key={step.key} className="flex items-center gap-1 flex-1">
              <div className={`flex items-center gap-1.5 ${isComplete ? 'text-primary' : 'text-muted-foreground/50'}`}>
                <div className={`flex h-7 w-7 items-center justify-center rounded-full border-2 transition-all ${
                  isCurrent ? 'border-primary bg-primary text-white' :
                  isComplete ? 'border-primary bg-primary/10' : 'border-muted'
                }`}>
                  <Icon className="h-3.5 w-3.5" />
                </div>
                <span className="text-[11px] font-medium hidden sm:inline">{step.label}</span>
              </div>
              {i < steps.length - 1 && (
                <div className={`h-0.5 flex-1 mx-1 ${i < stepIndex ? 'bg-primary' : 'bg-muted'}`} />
              )}
            </div>
          )
        })}
      </div>
      {/* Date labels */}
      <div className="flex justify-between mt-2 px-1">
        <span className="text-[10px] text-muted-foreground">
          {new Date(appliedAt).toLocaleDateString()}
        </span>
        {stepIndex > 0 && (
          <span className="text-[10px] text-muted-foreground">
            Updated {new Date(updatedAt).toLocaleDateString()}
          </span>
        )}
      </div>
    </div>
  )
}

function ApplicationCard({
  app,
  timeAgo,
  onWithdraw,
  onClick,
}: {
  app: Application
  timeAgo: (d: string) => string
  onWithdraw?: () => void
  onClick?: () => void
}) {
  const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const, icon: Clock }

  // Progress steps
  const steps = ['Applied', 'Reviewing', 'Interview', 'Offer']
  const currentStep = {
    applied: 0, reviewing: 1, shortlisted: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[app.status] ?? 0

  // Check if has screening answers
  let hasScreening = false
  try {
    const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers) : app.screening_answers
    hasScreening = answers && Object.keys(answers).length > 0
  } catch { /* ignore */ }

  return (
    <Card
      className="cursor-pointer transition-shadow hover:shadow-md"
      onClick={onClick}
    >
      <CardContent className="p-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{app.title}</h3>
              <Badge variant={config.variant}>{config.label}</Badge>
              {hasScreening && (
                <Badge variant="outline" className="gap-1 text-[10px]">
                  <ClipboardList className="h-3 w-3" /> Screening
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Building2 className="h-3.5 w-3.5" />
                {app.company || app.posted_by_company || 'Company'}
              </span>
              {app.location && (
                <span className="flex items-center gap-1">
                  <MapPin className="h-3.5 w-3.5" />
                  {app.location}
                </span>
              )}
              <span className="flex items-center gap-1">
                <Calendar className="h-3.5 w-3.5" />
                Applied {timeAgo(app.applied_at)}
              </span>
              {app.salary_range && (
                <span className="flex items-center gap-1">
                  <DollarSign className="h-3.5 w-3.5" />
                  {app.salary_range}
                </span>
              )}
            </div>

            {/* Progress timeline */}
            {currentStep >= 0 && (
              <div className="mt-3 flex items-center gap-1">
                {steps.map((step, i) => (
                  <div key={step} className="flex items-center gap-1">
                    <div className={`h-2 w-2 rounded-full ${
                      i === currentStep ? 'bg-primary ring-2 ring-primary/30' :
                      i < currentStep ? 'bg-primary' : 'bg-muted'
                    }`} />
                    <span className={`text-[10px] ${i <= currentStep ? 'text-foreground' : 'text-muted-foreground'}`}>
                      {step}
                    </span>
                    {i < steps.length - 1 && (
                      <div className={`h-px w-4 ${i < currentStep ? 'bg-primary' : 'bg-muted'}`} />
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {onWithdraw && !['rejected', 'withdrawn', 'hired'].includes(app.status) && (
              <Button
                variant="ghost"
                size="sm"
                onClick={e => {
                  e.stopPropagation()
                  onWithdraw()
                }}
                className="gap-1 text-muted-foreground hover:text-destructive"
              >
                <XCircle className="h-3.5 w-3.5" /> Withdraw
              </Button>
            )}
            <Link
              to={`/candidate/jobs/${app.job_id}`}
              onClick={e => e.stopPropagation()}
            >
              <Button variant="ghost" size="sm" className="gap-1 shrink-0">
                View Job <ExternalLink className="h-3 w-3" />
              </Button>
            </Link>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import { useEffect, useState } from 'react'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  Gift, DollarSign, Calendar, Building2, CheckCircle, XCircle, Clock, Eye,
} from 'lucide-react'

interface Offer {
  id: number
  title: string
  company_name: string
  company?: string
  job_title: string
  salary: number
  start_date: string
  benefits: string
  status: string
  sent_at: string
  viewed_at: string
  accepted_at: string
  declined_at: string
  decline_reason: string
  created_at: string
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: React.ElementType }> = {
  draft: { label: 'Draft', variant: 'secondary', icon: Clock },
  sent: { label: 'Pending', variant: 'warning', icon: Clock },
  viewed: { label: 'Viewed', variant: 'default', icon: Eye },
  accepted: { label: 'Accepted', variant: 'success', icon: CheckCircle },
  declined: { label: 'Declined', variant: 'destructive', icon: XCircle },
}

export function CandidateOffersPage() {
  const [offers, setOffers] = useState<Offer[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedOffer, setSelectedOffer] = useState<Offer | null>(null)
  const [declineDialog, setDeclineDialog] = useState(false)
  const [declineReason, setDeclineReason] = useState('')
  const [acting, setActing] = useState(false)

  useEffect(() => {
    loadOffers()
  }, [])

  async function loadOffers() {
    try {
      const data = await apiCall<Offer[]>('/onboarding/offers/me')
      setOffers(Array.isArray(data) ? data : [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function markViewed(offer: Offer) {
    if (!offer.viewed_at) {
      try {
        await apiCall(`/onboarding/offers/${offer.id}/view`, { method: 'POST' })
      } catch {
        // silent
      }
    }
    setSelectedOffer(offer)
  }

  async function acceptOffer() {
    if (!selectedOffer) return
    setActing(true)
    try {
      await apiCall(`/onboarding/offers/${selectedOffer.id}/accept`, { method: 'POST' })
      setSelectedOffer(null)
      loadOffers()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to accept offer')
    } finally {
      setActing(false)
    }
  }

  async function declineOffer() {
    if (!selectedOffer) return
    setActing(true)
    try {
      await apiCall(`/onboarding/offers/${selectedOffer.id}/decline`, {
        method: 'POST',
        body: { decline_reason: declineReason },
      })
      setDeclineDialog(false)
      setSelectedOffer(null)
      setDeclineReason('')
      loadOffers()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to decline offer')
    } finally {
      setActing(false)
    }
  }

  const pendingOffers = offers.filter(o => ['sent', 'viewed'].includes(o.status))
  const resolvedOffers = offers.filter(o => ['accepted', 'declined'].includes(o.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Offers</h1>
        <p className="text-muted-foreground">Review and respond to job offers</p>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : offers.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Gift className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No offers yet</p>
            <p className="text-sm text-muted-foreground mt-1">When a recruiter makes you an offer, it will appear here</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {pendingOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Pending Offers ({pendingOffers.length})
              </h2>
              <div className="space-y-3">
                {pendingOffers.map(offer => (
                  <OfferCard key={offer.id} offer={offer} onClick={() => markViewed(offer)} />
                ))}
              </div>
            </div>
          )}
          {resolvedOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Past Offers</h2>
              <div className="space-y-3">
                {resolvedOffers.map(offer => (
                  <OfferCard key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Offer detail dialog */}
      {selectedOffer && !declineDialog && (
        <Dialog open={true} onClose={() => setSelectedOffer(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedOffer.title || selectedOffer.job_title}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Company</p>
                <p className="font-medium">{selectedOffer.company_name || selectedOffer.company}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Position</p>
                <p className="font-medium">{selectedOffer.job_title || selectedOffer.title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Salary</p>
                <p className="font-medium text-emerald-600">
                  ${Number(selectedOffer.salary).toLocaleString()}/yr
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Start Date</p>
                <p className="font-medium">
                  {selectedOffer.start_date
                    ? new Date(selectedOffer.start_date).toLocaleDateString()
                    : 'TBD'}
                </p>
              </div>
            </div>
            {selectedOffer.benefits && (
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Benefits</p>
                <p className="text-sm whitespace-pre-wrap">{selectedOffer.benefits}</p>
              </div>
            )}

            {['sent', 'viewed'].includes(selectedOffer.status) && (
              <div className="flex gap-2 pt-2">
                <Button onClick={acceptOffer} disabled={acting} className="flex-1 gap-2">
                  <CheckCircle className="h-4 w-4" /> Accept Offer
                </Button>
                <Button
                  variant="outline"
                  onClick={() => setDeclineDialog(true)}
                  disabled={acting}
                  className="flex-1 gap-2"
                >
                  <XCircle className="h-4 w-4" /> Decline
                </Button>
              </div>
            )}

            {selectedOffer.status === 'accepted' && (
              <Badge variant="success" className="w-full justify-center py-2 text-sm">
                <CheckCircle className="h-4 w-4 mr-1" /> You accepted this offer
              </Badge>
            )}
            {selectedOffer.status === 'declined' && (
              <div>
                <Badge variant="destructive" className="w-full justify-center py-2 text-sm">
                  <XCircle className="h-4 w-4 mr-1" /> You declined this offer
                </Badge>
                {selectedOffer.decline_reason && (
                  <p className="text-sm text-muted-foreground mt-2">Reason: {selectedOffer.decline_reason}</p>
                )}
              </div>
            )}
          </div>
        </Dialog>
      )}

      {/* Decline reason dialog */}
      <Dialog open={declineDialog} onClose={() => setDeclineDialog(false)}>
        <DialogHeader>
          <DialogTitle>Decline Offer</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Are you sure you want to decline this offer? Please provide a reason (optional).
          </p>
          <Textarea
            placeholder="Reason for declining..."
            value={declineReason}
            onChange={e => setDeclineReason(e.target.value)}
            rows={3}
          />
          <div className="flex gap-2">
            <Button variant="destructive" onClick={declineOffer} disabled={acting} className="gap-2">
              {acting ? (
                <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                <XCircle className="h-4 w-4" />
              )}
              Confirm Decline
            </Button>
            <Button variant="outline" onClick={() => setDeclineDialog(false)}>Cancel</Button>
          </div>
        </div>
      </Dialog>
    </div>
  )
}

function OfferCard({ offer, onClick }: { offer: Offer; onClick: () => void }) {
  const config = statusConfig[offer.status] || { label: offer.status, variant: 'secondary' as const, icon: Clock }
  const Icon = config.icon

  return (
    <Card className="cursor-pointer transition-shadow hover:shadow-md" onClick={onClick}>
      <CardContent className="p-4">
        <div className="flex items-start justify-between">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold">{offer.title || offer.job_title}</h3>
              <Badge variant={config.variant} className="gap-1">
                <Icon className="h-3 w-3" /> {config.label}
              </Badge>
            </div>
            <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Building2 className="h-3.5 w-3.5" />
                {offer.company_name || offer.company}
              </span>
              <span className="flex items-center gap-1">
                <DollarSign className="h-3.5 w-3.5" />
                ${Number(offer.salary).toLocaleString()}/yr
              </span>
              {offer.start_date && (
                <span className="flex items-center gap-1">
                  <Calendar className="h-3.5 w-3.5" />
                  Start: {new Date(offer.start_date).toLocaleDateString()}
                </span>
              )}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs'
import {
  GraduationCap, Play, Trophy, Clock, Shield, AlertTriangle, CheckCircle,
} from 'lucide-react'

interface SkillCatalog {
  catalog_name: string
  category: string
  icon: string
  description: string
  difficulty: string
  skill_id: number | null
  is_verified: boolean
  verified_score: number | null
  assessment_count: number
  best_score: number | null
  last_attempted: string | null
}

interface AssessmentResult {
  id: number
  score: number
  max_score: number
  passed: boolean
  anti_cheat_score: number
  duration_seconds: number
  completed_at: string
  title: string
  skill_name: string
  category: string
  max_difficulty_reached: number
  tab_switches: number
  copy_paste_attempts: number
}

export function CandidateAssessmentsPage() {
  const navigate = useNavigate()
  const [tab, setTab] = useState('available')
  const [skills, setSkills] = useState<SkillCatalog[]>([])
  const [results, setResults] = useState<AssessmentResult[]>([])
  const [loading, setLoading] = useState(true)
  const [starting, setStarting] = useState<string | null>(null)

  useEffect(() => {
    loadData()
  }, [])

  async function loadData() {
    try {
      const [skillsRes, resultsRes] = await Promise.allSettled([
        apiCall<{ skills: SkillCatalog[] }>('/assessments/available'),
        apiCall<{ results: AssessmentResult[] }>('/assessments/results'),
      ])
      if (skillsRes.status === 'fulfilled') setSkills(skillsRes.value.skills || [])
      if (resultsRes.status === 'fulfilled') setResults(resultsRes.value.results || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function startAssessment(skill: SkillCatalog) {
    setStarting(skill.catalog_name)
    try {
      const data = await apiCall<{ sessionId: number; skillName: string; question: unknown }>('/assessments/start', {
        method: 'POST',
        body: {
          skillName: skill.catalog_name,
          category: skill.category,
          skillId: skill.skill_id,
        },
      })
      // Store the first question in sessionStorage so assessment-take can pick it up
      sessionStorage.setItem(`assessment_${data.sessionId}`, JSON.stringify({
        question: data.question,
        skillName: data.skillName || skill.catalog_name,
      }))
      navigate(`/candidate/assessments/${data.sessionId}/take`)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to start assessment')
    } finally {
      setStarting(null)
    }
  }

  const categoryGroups = skills.reduce((acc, s) => {
    const cat = s.category || 'other'
    if (!acc[cat]) acc[cat] = []
    acc[cat].push(s)
    return acc
  }, {} as Record<string, SkillCatalog[]>)

  const categoryLabels: Record<string, string> = {
    technical: 'Technical Skills',
    analytical: 'Analytical Skills',
    soft_skill: 'Soft Skills',
    other: 'Other',
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">Skill Assessments</h1>
        <p className="text-muted-foreground">Verify your skills with AI-powered assessments</p>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-3">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{results.length}</p>
            <p className="text-xs text-muted-foreground">Tests Taken</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {results.filter(r => r.passed).length}
            </p>
            <p className="text-xs text-muted-foreground">Passed</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {skills.filter(s => s.is_verified).length}
            </p>
            <p className="text-xs text-muted-foreground">Verified Skills</p>
          </CardContent>
        </Card>
      </div>

      <Tabs value={tab} onValueChange={setTab}>
        <TabsList>
          <TabsTrigger value="available">Available Tests</TabsTrigger>
          <TabsTrigger value="results">My Results</TabsTrigger>
        </TabsList>

        <TabsContent value="available">
          {loading ? (
            <div className="flex items-center justify-center py-16">
              <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
            </div>
          ) : (
            <div className="space-y-6 mt-4">
              {Object.entries(categoryGroups).map(([cat, catSkills]) => (
                <div key={cat}>
                  <h3 className="font-medium text-sm text-muted-foreground mb-3">
                    {categoryLabels[cat] || cat}
                  </h3>
                  <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
                    {catSkills.map(skill => (
                      <Card key={skill.catalog_name} className="relative">
                        <CardContent className="p-4">
                          <div className="flex items-start justify-between mb-2">
                            <div className="flex items-center gap-2">
                              <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-primary/10 text-primary font-mono font-bold text-xs">
                                {skill.icon}
                              </div>
                              <div>
                                <h4 className="font-medium text-sm">{skill.catalog_name}</h4>
                                <p className="text-xs text-muted-foreground">{skill.difficulty}</p>
                              </div>
                            </div>
                            {skill.is_verified && (
                              <Badge variant="success" className="text-[10px]">
                                <Shield className="h-3 w-3 mr-0.5" /> Verified
                              </Badge>
                            )}
                          </div>
                          <p className="text-xs text-muted-foreground mb-3">{skill.description}</p>
                          {skill.best_score !== null && (
                            <p className="text-xs mb-2">
                              Best: <span className="font-medium">{skill.best_score}/100</span>
                              <span className="text-muted-foreground ml-1">
                                ({skill.assessment_count} attempt{skill.assessment_count !== 1 ? 's' : ''})
                              </span>
                            </p>
                          )}
                          <Button
                            size="sm"
                            variant={skill.is_verified ? 'outline' : 'default'}
                            className="w-full gap-1"
                            onClick={() => startAssessment(skill)}
                            disabled={starting === skill.catalog_name}
                          >
                            {starting === skill.catalog_name ? (
                              <div className="h-3 w-3 animate-spin rounded-full border-2 border-current border-t-transparent" />
                            ) : (
                              <Play className="h-3 w-3" />
                            )}
                            {skill.is_verified ? 'Retake' : skill.assessment_count > 0 ? 'Try Again' : 'Start Test'}
                          </Button>
                        </CardContent>
                      </Card>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="results">
          {results.length === 0 ? (
            <Card className="mt-4">
              <CardContent className="py-16 text-center">
                <Trophy className="mx-auto mb-3 h-10 w-10 opacity-30" />
                <p className="text-muted-foreground">No assessment results yet</p>
                <Button className="mt-4" onClick={() => setTab('available')}>
                  Take a Test
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-3 mt-4">
              {results.map(r => (
                <Card key={r.id}>
                  <CardContent className="p-4">
                    <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <h4 className="font-medium">{r.skill_name || r.title}</h4>
                          {r.passed ? (
                            <Badge variant="success" className="gap-1">
                              <CheckCircle className="h-3 w-3" /> Passed
                            </Badge>
                          ) : (
                            <Badge variant="destructive" className="gap-1">
                              <AlertTriangle className="h-3 w-3" /> Failed
                            </Badge>
                          )}
                        </div>
                        <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
                          <span>Score: {r.score}/{r.max_score || 100}</span>
                          <span className="flex items-center gap-1">
                            <Clock className="h-3 w-3" />
                            {Math.round((r.duration_seconds || 0) / 60)} min
                          </span>
                          <span>Max difficulty: {r.max_difficulty_reached}/5</span>
                          <span>{new Date(r.completed_at).toLocaleDateString()}</span>
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="text-2xl font-bold">{r.score}%</div>
                        {r.anti_cheat_score < 80 && (
                          <span className="text-xs text-amber-600">Integrity: {r.anti_cheat_score}%</span>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </TabsContent>
      </Tabs>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select } from '@/components/ui/select'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  Gift, Plus, Send, DollarSign, Calendar, CheckCircle, XCircle, Clock, Eye,
  Ban, FileText, User, Briefcase, Building2,
} from 'lucide-react'

interface Offer {
  id: number
  candidate_id: number
  job_id: number
  title: string
  company_name: string
  candidate_name: string
  candidate_email: string
  job_title: string
  recruiter_name: string
  salary: number
  start_date: string
  benefits: string
  status: string
  sent_at: string
  viewed_at: string
  accepted_at: string
  declined_at: string
  decline_reason: string
  created_at: string
}

interface Candidate {
  id: number
  name: string
  email: string
}

interface Job {
  id: number
  title: string
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: React.ElementType }> = {
  draft: { label: 'Draft', variant: 'secondary', icon: Clock },
  sent: { label: 'Sent', variant: 'warning', icon: Send },
  viewed: { label: 'Viewed', variant: 'default', icon: Eye },
  accepted: { label: 'Accepted', variant: 'success', icon: CheckCircle },
  declined: { label: 'Declined', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: Ban },
}

export function RecruiterOffersPage() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [offers, setOffers] = useState<Offer[]>([])
  const [candidates, setCandidates] = useState<Candidate[]>([])
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreate, setShowCreate] = useState(false)
  const [saving, setSaving] = useState(false)
  const [sending, setSending] = useState<number | null>(null)
  const [selectedOffer, setSelectedOffer] = useState<Offer | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [statusFilter, setStatusFilter] = useState('')

  // Form fields
  const [candidateId, setCandidateId] = useState('')
  const [jobId, setJobId] = useState('')
  const [offerTitle, setOfferTitle] = useState('')
  const [salary, setSalary] = useState('')
  const [startDate, setStartDate] = useState('')
  const [benefits, setBenefits] = useState('')

  useEffect(() => {
    loadData()
  }, [])

  // Handle query params for pre-filled offer creation
  useEffect(() => {
    const create = searchParams.get('create')
    const cId = searchParams.get('candidateId')
    const jId = searchParams.get('jobId')
    const cName = searchParams.get('candidateName')

    if (create === '1') {
      if (cId) setCandidateId(cId)
      if (jId) setJobId(jId)
      setShowCreate(true)
      // Clean up URL params
      setSearchParams({}, { replace: true })
    }
  }, [searchParams])

  async function loadData() {
    try {
      const [offersRes, candidatesRes, jobsRes] = await Promise.allSettled([
        apiCall<Offer[]>('/onboarding/offers'),
        apiCall<{ candidates: Candidate[] }>('/recruiter/candidates'),
        apiCall<{ jobs: Job[] }>('/recruiter/jobs'),
      ])
      if (offersRes.status === 'fulfilled') setOffers(Array.isArray(offersRes.value) ? offersRes.value : [])
      if (candidatesRes.status === 'fulfilled') setCandidates(candidatesRes.value.candidates || [])
      if (jobsRes.status === 'fulfilled') setJobs(jobsRes.value.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function createOffer() {
    if (!candidateId || !jobId || !salary) {
      alert('Please fill in candidate, job, and salary')
      return
    }
    setSaving(true)
    try {
      await apiCall('/onboarding/offers', {
        method: 'POST',
        body: {
          candidate_id: Number(candidateId),
          job_id: Number(jobId),
          title: offerTitle || jobs.find(j => j.id === Number(jobId))?.title || 'Job Offer',
          salary: Number(salary),
          start_date: startDate || null,
          benefits,
        },
      })
      setShowCreate(false)
      resetForm()
      loadData()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to create offer')
    } finally {
      setSaving(false)
    }
  }

  async function sendOffer(id: number, e?: React.MouseEvent) {
    e?.stopPropagation()
    setSending(id)
    try {
      await apiCall(`/onboarding/offers/${id}/send`, { method: 'POST' })
      loadData()
      if (selectedOffer?.id === id) {
        setSelectedOffer(prev => prev ? { ...prev, status: 'sent', sent_at: new Date().toISOString() } : null)
      }
    } catch {
      // silent
    } finally {
      setSending(null)
    }
  }

  async function withdrawOffer(id: number) {
    if (!confirm('Are you sure you want to withdraw this offer?')) return
    setWithdrawing(true)
    try {
      await apiCall(`/onboarding/offers/${id}/withdraw`, { method: 'POST' })
      setSelectedOffer(null)
      loadData()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw offer')
    } finally {
      setWithdrawing(false)
    }
  }

  function resetForm() {
    setCandidateId('')
    setJobId('')
    setOfferTitle('')
    setSalary('')
    setStartDate('')
    setBenefits('')
  }

  const allStatuses = ['draft', 'sent', 'viewed', 'accepted', 'declined', 'withdrawn']
  const statusCounts = allStatuses.reduce((acc, s) => {
    acc[s] = offers.filter(o => o.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = offers.filter(o => !statusFilter || o.status === statusFilter)

  const draftOffers = filtered.filter(o => o.status === 'draft')
  const pendingOffers = filtered.filter(o => ['sent', 'viewed'].includes(o.status))
  const resolvedOffers = filtered.filter(o => ['accepted', 'declined', 'withdrawn'].includes(o.status))

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold">Offers</h1>
          <p className="text-muted-foreground">Create and manage job offers</p>
        </div>
        <Button onClick={() => setShowCreate(true)} className="gap-2">
          <Plus className="h-4 w-4" /> Create Offer
        </Button>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{offers.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {offers.filter(o => ['sent', 'viewed'].includes(o.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Pending</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {offers.filter(o => o.status === 'accepted').length}
            </p>
            <p className="text-xs text-muted-foreground">Accepted</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-destructive">
              {offers.filter(o => o.status === 'declined').length}
            </p>
            <p className="text-xs text-muted-foreground">Declined</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({offers.length})
        </Button>
        {allStatuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Gift className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">
              {offers.length === 0 ? 'No offers created yet' : 'No offers match this filter'}
            </p>
            {offers.length === 0 && (
              <Button onClick={() => setShowCreate(true)} className="gap-2">
                <Plus className="h-4 w-4" /> Create Your First Offer
              </Button>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {/* Draft offers */}
          {draftOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Drafts ({draftOffers.length})
              </h2>
              <div className="space-y-2">
                {draftOffers.map(offer => (
                  <OfferRow
                    key={offer.id}
                    offer={offer}
                    onSend={(e) => sendOffer(offer.id, e)}
                    sending={sending === offer.id}
                    onClick={() => setSelectedOffer(offer)}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Pending */}
          {pendingOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Pending Response ({pendingOffers.length})
              </h2>
              <div className="space-y-2">
                {pendingOffers.map(offer => (
                  <OfferRow key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}

          {/* Resolved */}
          {resolvedOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Resolved ({resolvedOffers.length})
              </h2>
              <div className="space-y-2">
                {resolvedOffers.map(offer => (
                  <OfferRow key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Offer detail dialog */}
      {selectedOffer && (
        <Dialog open={true} onClose={() => setSelectedOffer(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Gift className="h-5 w-5 text-primary" />
              Offer Details
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedOffer.status] || { label: selectedOffer.status, variant: 'secondary' as const, icon: Clock }
              const Icon = config.icon
              return (
                <Badge variant={config.variant} className="gap-1 w-fit">
                  <Icon className="h-3 w-3" /> {config.label}
                </Badge>
              )
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <User className="h-3 w-3" /> Candidate
                </p>
                <p className="font-medium">{selectedOffer.candidate_name || 'Unknown'}</p>
                <p className="text-xs text-muted-foreground">{selectedOffer.candidate_email}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Briefcase className="h-3 w-3" /> Position
                </p>
                <p className="font-medium">{selectedOffer.job_title || selectedOffer.title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <DollarSign className="h-3 w-3" /> Salary
                </p>
                <p className="font-medium text-emerald-600">
                  ${Number(selectedOffer.salary).toLocaleString()}/yr
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Start Date
                </p>
                <p className="font-medium">
                  {selectedOffer.start_date
                    ? new Date(selectedOffer.start_date).toLocaleDateString()
                    : 'TBD'}
                </p>
              </div>
            </div>

            {/* Benefits */}
            {selectedOffer.benefits && (
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Benefits</p>
                <p className="text-sm whitespace-pre-wrap">{selectedOffer.benefits}</p>
              </div>
            )}

            {/* Timeline */}
            <div className="rounded-lg border p-3 space-y-2">
              <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Timeline</p>
              <div className="space-y-1 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Created</span>
                  <span>{new Date(selectedOffer.created_at).toLocaleDateString()}</span>
                </div>
                {selectedOffer.sent_at && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Sent</span>
                    <span>{new Date(selectedOffer.sent_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.viewed_at && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Viewed</span>
                    <span>{new Date(selectedOffer.viewed_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.accepted_at && (
                  <div className="flex justify-between text-emerald-600">
                    <span>Accepted</span>
                    <span>{new Date(selectedOffer.accepted_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.declined_at && (
                  <div className="flex justify-between text-destructive">
                    <span>Declined</span>
                    <span>{new Date(selectedOffer.declined_at).toLocaleDateString()}</span>
                  </div>
                )}
              </div>
            </div>

            {/* Decline reason */}
            {selectedOffer.decline_reason && (
              <div className="rounded-lg bg-destructive/10 p-3">
                <p className="text-xs text-muted-foreground mb-1">Decline Reason</p>
                <p className="text-sm">{selectedOffer.decline_reason}</p>
              </div>
            )}

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              {selectedOffer.status === 'draft' && (
                <>
                  <Button
                    onClick={() => sendOffer(selectedOffer.id)}
                    disabled={sending === selectedOffer.id}
                    className="gap-2 flex-1"
                  >
                    {sending === selectedOffer.id ? (
                      <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                    ) : (
                      <Send className="h-4 w-4" />
                    )}
                    Send to Candidate
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => withdrawOffer(selectedOffer.id)}
                    disabled={withdrawing}
                    className="gap-2"
                  >
                    <Ban className="h-4 w-4" /> Delete
                  </Button>
                </>
              )}
              {['sent', 'viewed'].includes(selectedOffer.status) && (
                <Button
                  variant="outline"
                  onClick={() => withdrawOffer(selectedOffer.id)}
                  disabled={withdrawing}
                  className="gap-2 text-destructive"
                >
                  {withdrawing ? (
                    <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                  ) : (
                    <Ban className="h-4 w-4" />
                  )}
                  Withdraw Offer
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Create offer dialog */}
      <Dialog open={showCreate} onClose={() => { setShowCreate(false); resetForm() }} className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Create New Offer</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <div>
            <Label>Candidate *</Label>
            <Select value={candidateId} onChange={e => setCandidateId(e.target.value)} className="mt-1">
              <option value="">Select candidate...</option>
              {candidates.map(c => (
                <option key={c.id} value={c.id}>{c.name} ({c.email})</option>
              ))}
            </Select>
          </div>
          <div>
            <Label>Job Position *</Label>
            <Select value={jobId} onChange={e => setJobId(e.target.value)} className="mt-1">
              <option value="">Select job...</option>
              {jobs.map(j => (
                <option key={j.id} value={j.id}>{j.title}</option>
              ))}
            </Select>
          </div>
          <div>
            <Label>Offer Title</Label>
            <Input
              value={offerTitle}
              onChange={e => setOfferTitle(e.target.value)}
              placeholder="e.g. Senior Engineer Offer"
              className="mt-1"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Annual Salary ($) *</Label>
              <Input
                type="number"
                value={salary}
                onChange={e => setSalary(e.target.value)}
                placeholder="e.g. 120000"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Start Date</Label>
              <Input
                type="date"
                value={startDate}
                onChange={e => setStartDate(e.target.value)}
                className="mt-1"
              />
            </div>
          </div>
          <div>
            <Label>Benefits</Label>
            <Textarea
              value={benefits}
              onChange={e => setBenefits(e.target.value)}
              placeholder="Health insurance, 401k, PTO, etc..."
              rows={3}
              className="mt-1"
            />
          </div>
          <div className="flex gap-2 pt-2">
            <Button onClick={createOffer} disabled={saving} className="gap-2">
              {saving ? (
                <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                <Gift className="h-4 w-4" />
              )}
              Create Offer
            </Button>
            <Button variant="outline" onClick={() => { setShowCreate(false); resetForm() }}>Cancel</Button>
          </div>
        </div>
      </Dialog>
    </div>
  )
}

function OfferRow({ offer, onSend, sending, onClick }: {
  offer: Offer
  onSend?: (e: React.MouseEvent) => void
  sending?: boolean
  onClick?: () => void
}) {
  const config = statusConfig[offer.status] || { label: offer.status, variant: 'secondary' as const, icon: Clock }
  const Icon = config.icon

  return (
    <Card className="cursor-pointer transition-shadow hover:shadow-md" onClick={onClick}>
      <CardContent className="p-4">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <div className="min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{offer.candidate_name || 'Unknown'}</h3>
              <Badge variant={config.variant} className="gap-1">
                <Icon className="h-3 w-3" /> {config.label}
              </Badge>
            </div>
            <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
              <span className="flex items-center gap-1">
                <Briefcase className="h-3 w-3" />
                {offer.job_title || offer.title}
              </span>
              <span className="flex items-center gap-1">
                <DollarSign className="h-3 w-3" />
                ${Number(offer.salary).toLocaleString()}/yr
              </span>
              {offer.start_date && (
                <span className="flex items-center gap-1">
                  <Calendar className="h-3 w-3" />
                  Start: {new Date(offer.start_date).toLocaleDateString()}
                </span>
              )}
              {offer.decline_reason && (
                <span className="text-destructive">Reason: {offer.decline_reason}</span>
              )}
            </div>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {offer.status === 'draft' && onSend && (
              <Button size="sm" onClick={onSend} disabled={sending} className="gap-1">
                {sending ? (
                  <div className="h-3 w-3 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <Send className="h-3 w-3" />
                )}
                Send
              </Button>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

