import { useEffect, useState, useCallback, useRef } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import {
  Clock, AlertTriangle, CheckCircle, ArrowRight, Trophy, XCircle,
} from 'lucide-react'

interface Question {
  id: number
  text: string
  type: string
  options?: string[]
  timeLimit: number
  questionNumber: number
  totalQuestions: number
}

interface AnswerResult {
  completed: boolean
  feedback: string
  explanation: string
  aiFeedback?: string
  score?: number
  nextQuestion?: Question
}

interface SessionCurrentResponse {
  status: string
  skillName: string
  question?: Question
  score?: number
  passed?: boolean
  antiCheatScore?: number
  durationSeconds?: number
  maxDifficultyReached?: number
}

export function AssessmentTakePage() {
  const { id: sessionId } = useParams()
  const navigate = useNavigate()
  const [question, setQuestion] = useState<Question | null>(null)
  const [selectedAnswer, setSelectedAnswer] = useState('')
  const [shortAnswer, setShortAnswer] = useState('')
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [completed, setCompleted] = useState(false)
  const [finalScore, setFinalScore] = useState(0)
  const [passed, setPassed] = useState(false)
  const [timeLeft, setTimeLeft] = useState(0)
  const [skillName, setSkillName] = useState('')
  const [antiCheatScore, setAntiCheatScore] = useState(100)
  const [durationSeconds, setDurationSeconds] = useState(0)
  const [maxDifficulty, setMaxDifficulty] = useState(0)
  const startTimeRef = useRef(Date.now())

  useEffect(() => {
    loadSession()
  }, [sessionId])

  async function loadSession() {
    try {
      // Try sessionStorage first (set by assessments page when starting)
      const stored = sessionStorage.getItem(`assessment_${sessionId}`)
      if (stored) {
        const data = JSON.parse(stored)
        setQuestion(data.question)
        setSkillName(data.skillName || '')
        sessionStorage.removeItem(`assessment_${sessionId}`)
        setTimeLeft(data.question.timeLimit || 120)
        startTimeRef.current = Date.now()
        setLoading(false)
        return
      }

      // Fallback: fetch current session state from API (handles page refresh)
      const result = await apiCall<SessionCurrentResponse>(`/assessments/session/${sessionId}/current`)

      if (result.status === 'completed') {
        setCompleted(true)
        setFinalScore(result.score || 0)
        setPassed(result.passed || false)
        setSkillName(result.skillName || '')
        setAntiCheatScore(result.antiCheatScore || 100)
        setDurationSeconds(result.durationSeconds || 0)
        setMaxDifficulty(result.maxDifficultyReached || 0)
      } else if (result.status === 'in_progress' && result.question) {
        setQuestion(result.question)
        setSkillName(result.skillName || '')
        setTimeLeft(result.question.timeLimit || 120)
        startTimeRef.current = Date.now()
      } else {
        // Session abandoned or not found
        navigate('/candidate/assessments')
      }
    } catch {
      navigate('/candidate/assessments')
    } finally {
      setLoading(false)
    }
  }

  // Timer countdown
  useEffect(() => {
    if (!question || completed || timeLeft <= 0) return
    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timer)
          handleSubmit(true)
          return 0
        }
        return prev - 1
      })
    }, 1000)
    return () => clearInterval(timer)
  }, [question, completed])

  // Track tab switches
  useEffect(() => {
    function handleVisibility() {
      if (document.hidden && sessionId) {
        apiCall('/assessments/event', {
          method: 'POST',
          body: { sessionId: Number(sessionId), eventType: 'tab_switch', eventData: { timestamp: new Date() } },
        }).catch(() => {})
      }
    }
    document.addEventListener('visibilitychange', handleVisibility)
    return () => document.removeEventListener('visibilitychange', handleVisibility)
  }, [sessionId])

  // Track copy-paste
  useEffect(() => {
    function handleCopy() {
      if (sessionId) {
        apiCall('/assessments/event', {
          method: 'POST',
          body: { sessionId: Number(sessionId), eventType: 'copy_paste', eventData: { timestamp: new Date() } },
        }).catch(() => {})
      }
    }
    document.addEventListener('copy', handleCopy)
    document.addEventListener('paste', handleCopy)
    return () => {
      document.removeEventListener('copy', handleCopy)
      document.removeEventListener('paste', handleCopy)
    }
  }, [sessionId])

  const handleSubmit = useCallback(async (timedOut = false) => {
    if (!question || submitting) return
    setSubmitting(true)
    const timeTaken = Math.round((Date.now() - startTimeRef.current) / 1000)
    const answer = question.type === 'multiple_choice' ? selectedAnswer : shortAnswer

    if (!answer && !timedOut) {
      setSubmitting(false)
      return
    }

    try {
      const result = await apiCall<AnswerResult>('/assessments/answer', {
        method: 'POST',
        body: {
          sessionId: Number(sessionId),
          questionId: question.id,
          answer: answer || '(no answer)',
          timeTaken,
        },
      })

      if (result.completed) {
        // Fetch full results from API for accurate display
        try {
          const fullResult = await apiCall<SessionCurrentResponse>(`/assessments/session/${sessionId}/current`)
          setFinalScore(fullResult.score || result.score || 0)
          setPassed(fullResult.passed || (fullResult.score || 0) >= 60)
          setAntiCheatScore(fullResult.antiCheatScore || 100)
          setDurationSeconds(fullResult.durationSeconds || 0)
          setMaxDifficulty(fullResult.maxDifficultyReached || 0)
        } catch {
          setFinalScore(result.score || 0)
          setPassed((result.score || 0) >= 60)
        }
        setCompleted(true)
      } else if (result.nextQuestion) {
        setQuestion(result.nextQuestion)
        setSelectedAnswer('')
        setShortAnswer('')
        setTimeLeft(result.nextQuestion.timeLimit || 120)
        startTimeRef.current = Date.now()
      }
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to submit answer')
    } finally {
      setSubmitting(false)
    }
  }, [question, selectedAnswer, shortAnswer, sessionId, submitting])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
      </div>
    )
  }

  // Completed view with detailed results
  if (completed) {
    const isPassed = passed || finalScore >= 60
    const mins = Math.floor((durationSeconds || 0) / 60)
    return (
      <div className="max-w-lg mx-auto py-8">
        <Card>
          <CardContent className="p-8 text-center">
            {isPassed ? (
              <Trophy className="mx-auto h-16 w-16 text-emerald-500 mb-4" />
            ) : (
              <XCircle className="mx-auto h-16 w-16 text-destructive mb-4" />
            )}
            <h2 className="font-heading text-2xl font-bold mb-2">
              {isPassed ? 'Assessment Passed!' : 'Assessment Complete'}
            </h2>
            <p className="text-muted-foreground mb-6">
              {skillName && `${skillName} - `}
              {isPassed
                ? 'Great job! Your skill has been verified.'
                : 'Keep practicing and try again.'}
            </p>
            <div className="text-5xl font-bold mb-6">
              <span className={isPassed ? 'text-emerald-600' : 'text-destructive'}>
                {finalScore}
              </span>
              <span className="text-muted-foreground text-lg">/100</span>
            </div>
            <Badge variant={isPassed ? 'success' : 'destructive'} className="text-sm mb-6">
              {isPassed ? 'PASSED' : 'NOT PASSED'} (60 required)
            </Badge>

            {/* Detailed stats */}
            <div className="grid grid-cols-3 gap-3 mb-6 text-sm">
              {durationSeconds > 0 && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="font-medium">{mins}m {Math.round((durationSeconds || 0) % 60)}s</p>
                  <p className="text-xs text-muted-foreground">Duration</p>
                </div>
              )}
              {maxDifficulty > 0 && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="font-medium">{maxDifficulty}/5</p>
                  <p className="text-xs text-muted-foreground">Max Difficulty</p>
                </div>
              )}
              <div className="rounded-lg bg-muted/50 p-3">
                <p className={`font-medium ${antiCheatScore >= 80 ? 'text-emerald-600' : antiCheatScore >= 50 ? 'text-amber-600' : 'text-destructive'}`}>
                  {antiCheatScore}%
                </p>
                <p className="text-xs text-muted-foreground">Integrity</p>
              </div>
            </div>

            <div className="flex gap-2 justify-center">
              <Button onClick={() => navigate('/candidate/assessments')}>
                Back to Assessments
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  if (!question) {
    return (
      <div className="py-16 text-center">
        <p className="text-muted-foreground">Assessment session not found</p>
        <Button className="mt-4" onClick={() => navigate('/candidate/assessments')}>
          Back to Assessments
        </Button>
      </div>
    )
  }

  const minutes = Math.floor(timeLeft / 60)
  const seconds = timeLeft % 60
  const isLowTime = timeLeft < 30

  return (
    <div className="max-w-2xl mx-auto space-y-4">
      {/* Progress header */}
      <div className="flex items-center justify-between">
        <div>
          <span className="text-sm font-medium">
            Question {question.questionNumber} of {question.totalQuestions}
          </span>
          {skillName && (
            <span className="text-sm text-muted-foreground ml-2">- {skillName}</span>
          )}
        </div>
        <Badge variant={isLowTime ? 'destructive' : 'secondary'} className="gap-1 font-mono">
          <Clock className="h-3 w-3" />
          {minutes}:{seconds.toString().padStart(2, '0')}
        </Badge>
      </div>

      {/* Progress bar */}
      <div className="h-2 rounded-full bg-muted overflow-hidden">
        <div
          className="h-full bg-primary transition-all duration-300 rounded-full"
          style={{ width: `${(question.questionNumber / question.totalQuestions) * 100}%` }}
        />
      </div>

      {/* Question */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base leading-relaxed">{question.text}</CardTitle>
        </CardHeader>
        <CardContent>
          {question.type === 'multiple_choice' && question.options ? (
            <div className="space-y-2">
              {question.options.map((option, i) => (
                <button
                  key={i}
                  onClick={() => setSelectedAnswer(option)}
                  className={`w-full text-left rounded-lg border p-3 text-sm transition-colors ${
                    selectedAnswer === option
                      ? 'border-primary bg-primary/5 ring-1 ring-primary'
                      : 'hover:bg-muted'
                  }`}
                >
                  <span className="font-medium text-muted-foreground mr-2">
                    {String.fromCharCode(65 + i)}.
                  </span>
                  {option}
                </button>
              ))}
            </div>
          ) : (
            <Textarea
              value={shortAnswer}
              onChange={e => setShortAnswer(e.target.value)}
              placeholder="Type your answer here..."
              rows={6}
              className="font-mono text-sm"
            />
          )}
        </CardContent>
      </Card>

      {/* Submit */}
      <div className="flex justify-end">
        <Button
          onClick={() => handleSubmit(false)}
          disabled={submitting || (!selectedAnswer && !shortAnswer)}
          className="gap-2"
        >
          {submitting ? (
            <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
          ) : question.questionNumber === question.totalQuestions ? (
            <CheckCircle className="h-4 w-4" />
          ) : (
            <ArrowRight className="h-4 w-4" />
          )}
          {question.questionNumber === question.totalQuestions ? 'Finish' : 'Next'}
        </Button>
      </div>

      {isLowTime && (
        <div className="flex items-center gap-2 rounded-lg bg-destructive/10 p-3 text-sm text-destructive">
          <AlertTriangle className="h-4 w-4 shrink-0" />
          Time is running out! Answer will be auto-submitted when time expires.
        </div>
      )}
    </div>
  )
}

  useEffect(() => {
    loadData()
  }, [jobFilter])

  async function loadData() {
    try {
      const [appsPromise, jobsPromise] = await Promise.allSettled([
        (async () => {
          let url = '/recruiter/applications?limit=200'
          if (jobFilter) url += `&job_id=${jobFilter}`
          return apiCall<{ applications: Application[] }>(url)
        })(),
        apiCall<{ jobs: Job[] }>('/recruiter/jobs'),
      ])

      if (appsPromise.status === 'fulfilled') {
        setApplications(appsPromise.value.applications || [])
      }
      if (jobsPromise.status === 'fulfilled') {
        setJobs(jobsPromise.value.jobs || [])
      }
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(appId: number, newStatus: string) {
    setUpdating(true)
    try {
      await apiCall(`/recruiter/applications/${appId}`, {
        method: 'PUT',
        body: { status: newStatus, recruiter_notes: notes || undefined },
      })
      setApplications(prev =>
        prev.map(a => a.id === appId ? { ...a, status: newStatus } : a)
      )
      if (selected?.id === appId) {
        setSelected(prev => prev ? { ...prev, status: newStatus } : null)
      }
    } catch {
      // silent
    } finally {
      setUpdating(false)
    }
  }

  async function saveNotes() {
    if (!selected) return
    setUpdating(true)
    try {
      await apiCall(`/recruiter/applications/${selected.id}`, {
        method: 'PUT',
        body: { recruiter_notes: notes },
      })
      setApplications(prev =>
        prev.map(a => a.id === selected.id ? { ...a, recruiter_notes: notes } : a)
      )
    } catch {
      // silent
    } finally {
      setUpdating(false)
    }
  }

  function setJobFilter(jId: string) {
    if (jId) {
      setSearchParams({ job: jId }, { replace: true })
    } else {
      setSearchParams({}, { replace: true })
    }
  }

  function toggleSort(field: SortField) {
    if (sortField === field) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc')
    } else {
      setSortField(field)
      setSortDir('desc')
    }
  }

  // Apply all filters
  const filtered = applications
    .filter(a => !statusFilter || a.status === statusFilter)
    .filter(a => {
      if (!dateFrom && !dateTo) return true
      const d = new Date(a.applied_at).getTime()
      if (dateFrom && d < new Date(dateFrom).getTime()) return false
      if (dateTo && d > new Date(dateTo + 'T23:59:59').getTime()) return false
      return true
    })
    .filter(a => {
      if (!searchQuery) return true
      const q = searchQuery.toLowerCase()
      return (
        (a.candidate_name || '').toLowerCase().includes(q) ||
        (a.candidate_email || '').toLowerCase().includes(q) ||
        (a.job_title || '').toLowerCase().includes(q)
      )
    })
    .sort((a, b) => {
      let cmp = 0
      if (sortField === 'applied_at') {
        cmp = new Date(a.applied_at).getTime() - new Date(b.applied_at).getTime()
      } else if (sortField === 'candidate_name') {
        cmp = (a.candidate_name || '').localeCompare(b.candidate_name || '')
      } else if (sortField === 'match_score') {
        cmp = (a.match_score || 0) - (b.match_score || 0)
      }
      return sortDir === 'asc' ? cmp : -cmp
    })

  // Group counts
  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applications.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  const selectedJob = jobs.find(j => j.id === Number(jobFilter))
  const hasActiveFilters = statusFilter || dateFrom || dateTo || searchQuery

  function openDetail(app: Application) {
    setSelected(app)
    setNotes(app.recruiter_notes || '')
  }

  function clearAllFilters() {
    setStatusFilter('')
    setDateFrom('')
    setDateTo('')
    setSearchQuery('')
    setJobFilter('')
  }

  return (
    <div className="space-y-6">
      <div className="flex items-start justify-between gap-4">
        <div>
          <h1 className="font-heading text-2xl font-bold">Applications</h1>
          <p className="text-muted-foreground">
            Review and manage candidate applications
          </p>
        </div>
        {/* Job filter dropdown */}
        <div className="shrink-0 w-56">
          <Select
            value={jobFilter}
            onChange={e => setJobFilter(e.target.value)}
            className="text-sm"
          >
            <option value="">All Jobs</option>
            {jobs.map(j => (
              <option key={j.id} value={j.id}>{j.title}</option>
            ))}
          </Select>
        </div>
      </div>

      {/* Active job filter banner */}
      {jobFilter && selectedJob && (
        <div className="flex items-center gap-2 rounded-lg bg-primary/5 border border-primary/20 px-4 py-2">
          <Briefcase className="h-4 w-4 text-primary" />
          <span className="text-sm">
            Showing applications for: <strong>{selectedJob.title}</strong>
          </span>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setJobFilter('')}
            className="ml-auto gap-1 h-7"
          >
            <X className="h-3 w-3" /> Clear
          </Button>
        </div>
      )}

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applications.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {applications.filter(a => a.status === 'applied').length}
            </p>
            <p className="text-xs text-muted-foreground">New</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {applications.filter(a => ['reviewing', 'shortlisted', 'interviewed'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">In Pipeline</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {applications.filter(a => ['offered', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Offered / Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Filters section */}
      <div className="space-y-3">
        {/* Search + Date filters row */}
        <div className="flex flex-wrap gap-3 items-end">
          <div className="flex-1 min-w-[200px]">
            <label className="text-xs font-medium text-muted-foreground mb-1 block">Search</label>
            <Input
              placeholder="Search by name, email, or job..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="text-sm"
            />
          </div>
          <div className="w-40">
            <label className="text-xs font-medium text-muted-foreground mb-1 block">From Date</label>
            <Input
              type="date"
              value={dateFrom}
              onChange={e => setDateFrom(e.target.value)}
              className="text-sm"
            />
          </div>
          <div className="w-40">
            <label className="text-xs font-medium text-muted-foreground mb-1 block">To Date</label>
            <Input
              type="date"
              value={dateTo}
              onChange={e => setDateTo(e.target.value)}
              className="text-sm"
            />
          </div>
          {hasActiveFilters && (
            <Button variant="ghost" size="sm" onClick={clearAllFilters} className="gap-1 text-muted-foreground">
              <X className="h-3 w-3" /> Clear Filters
            </Button>
          )}
        </div>

        {/* Status filter pills */}
        <div className="flex flex-wrap gap-2">
          <Button
            variant={!statusFilter ? 'default' : 'outline'}
            size="sm"
            onClick={() => setStatusFilter('')}
          >
            All ({applications.length})
          </Button>
          {statuses.map(s => (
            statusCounts[s] > 0 && (
              <Button
                key={s}
                variant={statusFilter === s ? 'default' : 'outline'}
                size="sm"
                onClick={() => setStatusFilter(s)}
              >
                {statusConfig[s]?.label || s} ({statusCounts[s]})
              </Button>
            )
          ))}
        </div>
      </div>

      {/* Sort controls */}
      <div className="flex items-center gap-3 text-xs text-muted-foreground">
        <span className="font-medium">Sort:</span>
        <SortButton field="applied_at" label="Date" current={sortField} dir={sortDir} onToggle={toggleSort} />
        <SortButton field="candidate_name" label="Name" current={sortField} dir={sortDir} onToggle={toggleSort} />
        <SortButton field="match_score" label="Match" current={sortField} dir={sortDir} onToggle={toggleSort} />
        <span className="ml-auto">{filtered.length} application{filtered.length !== 1 ? 's' : ''}</span>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <FileText className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">
              {applications.length === 0 ? 'No applications yet' : 'No applications match your filters'}
            </p>
            {hasActiveFilters && (
              <Button variant="outline" size="sm" onClick={clearAllFilters} className="mt-3 gap-1">
                <X className="h-3 w-3" /> Clear Filters
              </Button>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-2">
          {filtered.map(app => {
            const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const }
            return (
              <Card
                key={app.id}
                className="cursor-pointer transition-shadow hover:shadow-md"
                onClick={() => openDetail(app)}
              >
                <CardContent className="p-4">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <div className="min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-semibold truncate">{app.candidate_name || 'Unknown'}</h3>
                        <Badge variant={config.variant}>{config.label}</Badge>
                        {hasScreeningAnswers(app) && (
                          <Badge variant="outline" className="gap-1 text-[10px]">
                            <ClipboardList className="h-3 w-3" /> Screening
                          </Badge>
                        )}
                      </div>
                      <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
                        <span className="flex items-center gap-1">
                          <Briefcase className="h-3 w-3" />
                          {app.job_title}
                        </span>
                        <span>{app.candidate_email}</span>
                        <span className="flex items-center gap-1">
                          <Calendar className="h-3 w-3" />
                          {new Date(app.applied_at).toLocaleDateString()}
                        </span>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 shrink-0">
                      {app.match_score && (
                        <div className="text-center">
                          <div className="text-lg font-bold text-primary">{app.match_score}%</div>
                          <div className="text-[10px] text-muted-foreground">Match</div>
                        </div>
                      )}
                      {app.verified_skills_count !== undefined && app.verified_skills_count > 0 && (
                        <Badge variant="outline" className="gap-1 text-[10px]">
                          <GraduationCap className="h-3 w-3" /> {app.verified_skills_count} verified
                        </Badge>
                      )}
                      <Select
                        value={app.status}
                        onChange={e => {
                          e.stopPropagation()
                          updateStatus(app.id, e.target.value)
                        }}
                        onClick={e => e.stopPropagation()}
                        className="w-32 text-xs"
                      >
                        {statuses.map(s => (
                          <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                        ))}
                      </Select>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )
          })}
        </div>
      )}

      {/* Application detail dialog */}
      {selected && (
        <Dialog open={true} onClose={() => setSelected(null)} className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Application: {selected.candidate_name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Position</p>
                <p className="font-medium">{selected.job_title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Email</p>
                <p className="font-medium text-sm">{selected.candidate_email}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Applied</p>
                <p className="font-medium">{new Date(selected.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Match Score</p>
                <p className="font-medium">{selected.match_score ? `${selected.match_score}%` : 'N/A'}</p>
              </div>
            </div>

            {/* Cover letter */}
            {selected.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1">Cover Letter</h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap max-h-40 overflow-y-auto">
                  {selected.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            <ScreeningAnswersBlock app={selected} />

            {/* Candidate stats */}
            <div className="flex flex-wrap gap-2">
              {selected.verified_skills_count !== undefined && selected.verified_skills_count > 0 && (
                <Badge variant="outline" className="gap-1">
                  <GraduationCap className="h-3 w-3" /> {selected.verified_skills_count} verified skills
                </Badge>
              )}
              {selected.completed_interviews !== undefined && selected.completed_interviews > 0 && (
                <Badge variant="outline" className="gap-1">
                  <MessageSquare className="h-3 w-3" /> {selected.completed_interviews} interviews done
                </Badge>
              )}
              {selected.current_omniscore && (
                <Badge variant="outline" className="gap-1">
                  <Star className="h-3 w-3" /> OmniScore: {selected.current_omniscore}
                </Badge>
              )}
            </div>

            {/* Notes */}
            <div>
              <h4 className="font-medium text-sm mb-1">Recruiter Notes</h4>
              <Textarea
                value={notes}
                onChange={e => setNotes(e.target.value)}
                placeholder="Add notes about this candidate..."
                rows={3}
              />
            </div>

            {/* Status change + actions */}
            <div className="flex items-center gap-3 pt-2">
              <span className="text-sm font-medium">Status:</span>
              <Select
                value={selected.status}
                onChange={e => updateStatus(selected.id, e.target.value)}
                className="w-40"
                disabled={updating}
              >
                {statuses.map(s => (
                  <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                ))}
              </Select>
              <Button
                size="sm"
                variant="outline"
                onClick={() => {
                  saveNotes()
                  setSelected(null)
                }}
                disabled={updating}
              >
                Save & Close
              </Button>
            </div>

            {/* Make Offer button */}
            {!['rejected', 'offered', 'hired'].includes(selected.status) && (
              <Button
                className="w-full gap-2"
                onClick={() => {
                  navigate(`/recruiter/offers?create=1&candidateId=${selected.candidate_id}&jobId=${selected.job_id}`)
                }}
              >
                <Gift className="h-4 w-4" /> Make Offer to {selected.candidate_name?.split(' ')[0] || 'Candidate'}
              </Button>
            )}
          </div>
        </Dialog>
      )}
    </div>
  )
}

function hasScreeningAnswers(app: Application): boolean {
  try {
    const answers = typeof app.screening_answers === 'string'
      ? JSON.parse(app.screening_answers)
      : app.screening_answers
    return answers && Object.keys(answers).length > 0
  } catch {
    return false
  }
}

function ScreeningAnswersBlock({ app }: { app: Application }) {
  try {
    const answers = typeof app.screening_answers === 'string'
      ? JSON.parse(app.screening_answers)
      : app.screening_answers
    const questions = app.screening_questions
      ? (typeof app.screening_questions === 'string'
        ? JSON.parse(app.screening_questions)
        : app.screening_questions)
      : []
    if (!answers || Object.keys(answers).length === 0) return null
    return (
      <div>
        <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
          <ClipboardList className="h-4 w-4 text-primary" />
          Screening Answers
        </h4>
        <div className="space-y-2">
          {Object.entries(answers).map(([key, value], i) => {
            const q = questions[i]
            return (
              <div key={key} className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1 font-medium">
                  {q?.question || q || `Question ${i + 1}`}
                </p>
                <p className="text-sm">{String(value)}</p>
              </div>
            )
          })}
        </div>
      </div>
    )
  } catch {
    return null
  }
}

function SortButton({
  field,
  label,
  current,
  dir,
  onToggle,
}: {
  field: SortField
  label: string
  current: SortField
  dir: SortDir
  onToggle: (f: SortField) => void
}) {
  const isActive = current === field
  return (
    <button
      onClick={() => onToggle(field)}
      className={`flex items-center gap-1 px-2 py-1 rounded hover:bg-muted transition-colors ${
        isActive ? 'text-foreground font-medium' : ''
      }`}
    >
      {label}
      {isActive ? (
        dir === 'asc' ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />
      ) : (
        <ArrowUpDown className="h-3 w-3 opacity-40" />
      )}
    </button>
  )
}

