// Create feedback survey (auto-scheduled by system)
router.post('/feedback/schedule', authMiddleware, async (req, res) => {
  try {
    const { employee_id, day_mark } = req.body;

    const questions = {
      30: [
        'How would you rate your onboarding experience?',
